// A script file (no top-level import/export): its top-level `declare`s are
// global, and `declare module "timers"` is a real ambient module — the
// shape real @types/node uses. The NodeJS namespace here merges with the
// `declare global { namespace NodeJS }` blocks in globals.d.ts/process.d.ts.
declare namespace NodeJS {
  interface Timeout {
    hasRef(): boolean;
    refresh(): Timeout;
  }
}
declare module "timers" {
  export function setTimeout(callback: () => void, ms: number): NodeJS.Timeout;
  export function clearTimeout(timeout: NodeJS.Timeout): void;
}
